/**
 * @name Taint flow from HTTP input to file system operations
 * @description User-controlled input flowing to file system operations without adequate validation
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-http-to-file
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File/Path constructors
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // FileInputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal: user input flows to file operation from $@.", source.getNode(), "user-controlled source"

/**
 * @name HTTP input to classpath resource loading - all sources
 * @description Find all cases where HTTP request data flows to ClassLoader.getResource/getResourceAsStream
 * @kind path-problem
 * @problem.severity error
 * @id java/http-to-classloader-resource
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ClasspathResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream", "getSystemResource", "getSystemResourceAsStream"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") or
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ClasspathResourceFlow = TaintTracking::Global<ClasspathResourceConfig>;
import ClasspathResourceFlow::PathGraph

from ClasspathResourceFlow::PathNode source, ClasspathResourceFlow::PathNode sink
where ClasspathResourceFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP input flows to ClassLoader resource loading from $@.", source.getNode(), "user-controlled source"

/**
 * @name Additional path traversal patterns - request parameter to file operations
 * @description Find request parameters flowing to file/path operations beyond OpenApiInterceptor
 * @kind path-problem
 * @problem.severity error
 * @id java/request-param-to-file
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module RequestParamFileConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName(["getParameter", "getParameterValues", "getParameterMap", "getHeader", "getHeaders"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      (ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") or
       ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream")) and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    exists(MethodCall mc |
      (mc.getMethod().hasName("get") and mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths")) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasName("ClasspathUtil") and
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Exclude OpenApiInterceptor results already found
    node.getEnclosingCallable().getDeclaringType().hasName("OpenApiInterceptor")
  }
}

module RequestParamFileFlow = TaintTracking::Global<RequestParamFileConfig>;
import RequestParamFileFlow::PathGraph

from RequestParamFileFlow::PathNode source, RequestParamFileFlow::PathNode sink
where RequestParamFileFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP request parameter flows to file/path operation from $@.", source.getNode(), "HTTP request parameter"
